import { useState, useEffect, FormEvent, CSSProperties } from "react";
import API from "./API.tsx";

interface ProfilePageProps {
  onComplete: () => void;
}

interface ProfileForm {
  name: string;
  address: string;
  city: string;
  phone: string;
}

export default function ProfilePage({ onComplete }: ProfilePageProps) {
  const [form, setForm] = useState<ProfileForm>({
    name: "",
    address: "",
    city: "",
    phone: "",
  });
  const [error, setError] = useState<string>("");
  const [loading, setLoading] = useState<boolean>(false);
  const [fetching, setFetching] = useState<boolean>(true);

  const [email, setEmail] = useState<string>(localStorage.getItem("email") || "");

  // ── Fetch user from DB on mount ──────────────────────────────────────────
  useEffect(() => {
    const loadUser = async () => {
      try {
        const res = await API.get("auth/users/me/");
        const { name, email: serverEmail } = res.data;

        // Restore localStorage fields (device-only)
        const saved = JSON.parse(localStorage.getItem("profile") || "{}");

        setEmail(serverEmail || email);
        setForm({
          name: name || "",
          address: saved.address || "",
          city: saved.city || "",
          phone: saved.phone || "",
        });
      } catch {
        // Silently fall back to whatever is in localStorage
      } finally {
        setFetching(false);
      }
    };

    loadUser();
  }, []);

  const handleChange = (field: keyof ProfileForm) =>
    (e: React.ChangeEvent<HTMLInputElement>) =>
      setForm((prev) => ({ ...prev, [field]: e.target.value }));

  const handleSubmit = async (e: FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    setError("");
    setLoading(true);
    try {
      await API.patch("auth/users/me/", { name: form.name });
      localStorage.setItem("profile", JSON.stringify(form));
      onComplete();
    } catch (err: any) {
      setError(err.response?.data?.detail || "Failed to save profile.");
    } finally {
      setLoading(false);
    }
  };

  const handleSkip = () => {
    localStorage.setItem("profile", JSON.stringify(form));
    onComplete();
  };

  if (fetching) {
    return (
      <div style={styles.loadingRoot}>
        <span style={styles.loadingSpinner} />
        <p style={styles.loadingText}>Loading your profile…</p>
      </div>
    );
  }

  return (
    <div style={styles.root}>
      <div style={styles.bg} aria-hidden="true" />

      <div style={styles.layout}>
        {/* ── Sidebar ── */}
        <div style={styles.sidebar}>
          <div style={styles.sidebarInner}>
            <div style={styles.logoRow}>
              <div style={styles.logoMark}>
                <svg width="22" height="22" viewBox="0 0 22 22" fill="none">
                  <rect x="1" y="1" width="9" height="9" rx="2" fill="#e8d5c4" />
                  <rect x="12" y="1" width="9" height="9" rx="2" fill="#c9b8a8" opacity="0.6" />
                  <rect x="1" y="12" width="9" height="9" rx="2" fill="#c9b8a8" opacity="0.6" />
                  <rect x="12" y="12" width="9" height="9" rx="2" fill="#e8d5c4" />
                </svg>
              </div>
              <span style={styles.logoText}>TaskFlow</span>
            </div>

            <div style={styles.avatarWrap}>
              <div style={styles.avatar}>
                {form.name ? form.name.charAt(0).toUpperCase() : "?"}
              </div>
              <p style={styles.avatarName}>{form.name || "Your Name"}</p>
              <p style={styles.avatarEmail}>{email}</p>
            </div>

            <div style={styles.steps}>
              {[
                { label: "Name", hint: "Saved to your account" },
                { label: "Location", hint: "Stored locally" },
                { label: "Contact", hint: "Stored locally" },
              ].map((s, i) => (
                <div key={i} style={styles.step}>
                  <div style={styles.stepDot} />
                  <div>
                    <span style={styles.stepLabel}>{s.label}</span>
                    <span style={styles.stepHint}>{s.hint}</span>
                  </div>
                </div>
              ))}
            </div>
          </div>
        </div>

        {/* ── Form card ── */}
        <div style={styles.card}>
          <h1 style={styles.heading}>Set up your profile</h1>
          <p style={styles.subheading}>
            Your name is saved to your account. Address, city, and phone are
            stored locally on this device only.
          </p>

          {error && <div style={styles.errorBox}>{error}</div>}

          <form onSubmit={handleSubmit} style={styles.form}>
            {/* ── Personal info (DB) ── */}
            <div style={styles.section}>
              <p style={styles.sectionLabel}>Personal info · Saved to account</p>
              <div style={styles.field}>
                <label style={styles.label} htmlFor="name">Full name</label>
                <input
                  id="name"
                  type="text"
                  autoFocus
                  placeholder="e.g. Juan dela Cruz"
                  value={form.name}
                  onChange={handleChange("name")}
                  style={styles.input}
                />
              </div>
              <div style={styles.field}>
                <label style={styles.label} htmlFor="email-display">Email address</label>
                <input
                  id="email-display"
                  type="email"
                  value={email}
                  disabled
                  style={{ ...styles.input, ...styles.inputDisabled }}
                />
              </div>
            </div>

            <div style={styles.divider} />

            {/* ── Location (localStorage only) ── */}
            <div style={styles.section}>
              <div style={styles.sectionLabelRow}>
                <p style={styles.sectionLabel}>Location</p>
                <span style={styles.localBadge}>Device only</span>
              </div>
              <div style={styles.field}>
                <label style={styles.label} htmlFor="address">Street address</label>
                <input
                  id="address"
                  type="text"
                  placeholder="e.g. 123 Rizal Ave"
                  value={form.address}
                  onChange={handleChange("address")}
                  style={styles.input}
                />
              </div>
              <div style={styles.field}>
                <label style={styles.label} htmlFor="city">City</label>
                <input
                  id="city"
                  type="text"
                  placeholder="e.g. Quezon City"
                  value={form.city}
                  onChange={handleChange("city")}
                  style={styles.input}
                />
              </div>
            </div>

            <div style={styles.divider} />

            {/* ── Contact (localStorage only) ── */}
            <div style={styles.section}>
              <div style={styles.sectionLabelRow}>
                <p style={styles.sectionLabel}>Contact</p>
                <span style={styles.localBadge}>Device only</span>
              </div>
              <div style={styles.field}>
                <label style={styles.label} htmlFor="phone">Phone number</label>
                <input
                  id="phone"
                  type="tel"
                  placeholder="e.g. +63 912 345 6789"
                  value={form.phone}
                  onChange={handleChange("phone")}
                  style={styles.input}
                />
              </div>
            </div>

            <div style={styles.actions}>
              <button type="button" onClick={handleSkip} style={styles.skipBtn}>
                Skip for now
              </button>
              <button type="submit" disabled={loading} style={styles.submitBtn}>
                {loading ? <span style={styles.spinner} /> : "Save & continue →"}
              </button>
            </div>
          </form>
        </div>
      </div>

      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Lora:ital@0;1&family=DM+Sans:wght@400;500&display=swap');
        * { box-sizing: border-box; margin: 0; padding: 0; }
        input::placeholder { color: #bbb0a4; }
        input:focus { outline: none; border-color: #c4a882 !important; box-shadow: 0 0 0 3px rgba(196,168,130,0.18); }
        @keyframes spin { to { transform: rotate(360deg); } }
        @keyframes fadeUp {
          from { opacity: 0; transform: translateY(16px); }
          to   { opacity: 1; transform: translateY(0); }
        }
      `}</style>
    </div>
  );
}

const styles: Record<string, CSSProperties> = {
  loadingRoot: {
    minHeight: "100vh",
    display: "flex",
    flexDirection: "column",
    alignItems: "center",
    justifyContent: "center",
    background: "#f5f0eb",
    gap: "12px",
  },
  loadingSpinner: {
    width: "28px",
    height: "28px",
    border: "3px solid #ddd4c8",
    borderTop: "3px solid #c4a882",
    borderRadius: "50%",
    animation: "spin 0.7s linear infinite",
    display: "inline-block",
  },
  loadingText: {
    fontSize: "14px",
    color: "#9c8c7c",
    fontFamily: "'DM Sans', sans-serif",
  },
  root: {
    minHeight: "100vh",
    background: "#f5f0eb",
    display: "flex",
    alignItems: "center",
    justifyContent: "center",
    fontFamily: "'DM Sans', sans-serif",
    position: "relative",
    padding: "2rem 1rem",
  },
  bg: {
    position: "absolute",
    inset: 0,
    backgroundImage:
      "linear-gradient(rgba(180,160,140,0.12) 1px, transparent 1px), linear-gradient(90deg, rgba(180,160,140,0.12) 1px, transparent 1px)",
    backgroundSize: "40px 40px",
    pointerEvents: "none",
  },
  layout: {
    display: "flex",
    width: "100%",
    maxWidth: "860px",
    borderRadius: "20px",
    overflow: "hidden",
    boxShadow: "0 4px 40px rgba(120,90,60,0.10)",
    position: "relative",
    animation: "fadeUp 0.45s ease both",
  },
  sidebar: {
    width: "240px",
    flexShrink: 0,
    background: "#3d2e20",
    display: "flex",
    flexDirection: "column",
  },
  sidebarInner: {
    padding: "2rem 1.5rem",
    display: "flex",
    flexDirection: "column",
    gap: "2rem",
  },
  logoRow: { display: "flex", alignItems: "center", gap: "8px" },
  logoMark: {
    width: "32px",
    height: "32px",
    background: "rgba(255,255,255,0.1)",
    borderRadius: "8px",
    display: "flex",
    alignItems: "center",
    justifyContent: "center",
  },
  logoText: {
    fontFamily: "'Lora', serif",
    fontSize: "17px",
    color: "#f5ede2",
    letterSpacing: "-0.3px",
  },
  avatarWrap: {
    display: "flex",
    flexDirection: "column",
    alignItems: "center",
    gap: "6px",
    padding: "1.25rem 0",
    borderTop: "1px solid rgba(255,255,255,0.1)",
    borderBottom: "1px solid rgba(255,255,255,0.1)",
  },
  avatar: {
    width: "60px",
    height: "60px",
    borderRadius: "50%",
    background: "#c4a882",
    display: "flex",
    alignItems: "center",
    justifyContent: "center",
    fontSize: "24px",
    fontWeight: "500",
    color: "#3d2e20",
    marginBottom: "4px",
  },
  avatarName: { fontSize: "14px", fontWeight: "500", color: "#f5ede2", textAlign: "center" },
  avatarEmail: { fontSize: "12px", color: "rgba(245,237,226,0.55)", textAlign: "center", wordBreak: "break-all" },
  steps: { display: "flex", flexDirection: "column", gap: "14px" },
  step: { display: "flex", alignItems: "flex-start", gap: "10px" },
  stepDot: { width: "8px", height: "8px", borderRadius: "50%", background: "#c4a882", flexShrink: 0, marginTop: "3px" },
  stepLabel: { fontSize: "13px", color: "rgba(245,237,226,0.7)", display: "block" },
  stepHint: { fontSize: "11px", color: "rgba(245,237,226,0.35)", display: "block", marginTop: "1px" },
  card: {
    flex: 1,
    background: "#fffefb",
    padding: "2.5rem 2.25rem",
    overflowY: "auto" as const,
  },
  heading: {
    fontFamily: "'Lora', serif",
    fontSize: "24px",
    fontWeight: "400",
    color: "#2a1f14",
    letterSpacing: "-0.4px",
    marginBottom: "6px",
  },
  subheading: {
    fontSize: "14px",
    color: "#9c8c7c",
    marginBottom: "1.75rem",
    lineHeight: "1.5",
  },
  errorBox: {
    background: "#fef3f3",
    border: "1px solid #f5c4c4",
    borderRadius: "8px",
    padding: "10px 12px",
    fontSize: "13px",
    color: "#8a3030",
    marginBottom: "1.25rem",
  },
  form: { display: "flex", flexDirection: "column", gap: "1.25rem" },
  section: { display: "flex", flexDirection: "column", gap: "0.75rem" },
  sectionLabelRow: { display: "flex", alignItems: "center", gap: "8px" },
  sectionLabel: {
    fontSize: "11px",
    fontWeight: "500",
    color: "#c4a882",
    letterSpacing: "0.08em",
    textTransform: "uppercase" as const,
  },
  localBadge: {
    fontSize: "10px",
    background: "#f0ece7",
    color: "#9c8c7c",
    borderRadius: "4px",
    padding: "2px 6px",
    letterSpacing: "0.03em",
  },
  field: { display: "flex", flexDirection: "column", gap: "5px" },
  label: { fontSize: "13px", fontWeight: "500", color: "#6b5a4a" },
  input: {
    width: "100%",
    padding: "10px 14px",
    fontSize: "14px",
    color: "#2a1f14",
    background: "#faf8f5",
    border: "1px solid #ddd4c8",
    borderRadius: "9px",
    transition: "border-color 0.15s, box-shadow 0.15s",
    fontFamily: "'DM Sans', sans-serif",
  },
  inputDisabled: { background: "#f0ece7", color: "#9c8c7c", cursor: "not-allowed" },
  divider: { height: "1px", background: "#ede8e2" },
  actions: { display: "flex", gap: "10px", justifyContent: "flex-end", marginTop: "0.5rem" },
  skipBtn: {
    padding: "10px 18px",
    background: "none",
    border: "1px solid #ddd4c8",
    borderRadius: "10px",
    fontSize: "13px",
    color: "#9c8c7c",
    cursor: "pointer",
    fontFamily: "'DM Sans', sans-serif",
  },
  submitBtn: {
    padding: "10px 22px",
    background: "#3d2e20",
    color: "#f5ede2",
    border: "none",
    borderRadius: "10px",
    fontSize: "14px",
    fontWeight: "500",
    fontFamily: "'DM Sans', sans-serif",
    cursor: "pointer",
    display: "flex",
    alignItems: "center",
    gap: "6px",
    letterSpacing: "0.01em",
  },
  spinner: {
    width: "14px",
    height: "14px",
    border: "2px solid rgba(245,237,226,0.3)",
    borderTop: "2px solid #f5ede2",
    borderRadius: "50%",
    animation: "spin 0.7s linear infinite",
    display: "inline-block",
  },
};
